<svg viewBox="0 0 700 260" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">ETHストラドル損益分岐点(行使価格$1,875・7月24日満期)</text>
  <line x1="60" y1="150" x2="640" y2="150" stroke="#3f3f46" stroke-width="2"/>
